  1→import { useEffect, useRef, useState } from "react";
  2→import { MoonLoader } from "react-spinners";
  3→import { useQuery } from "@tanstack/react-query";
  4→import { useNavigate } from "react-router-dom";
  5→import { motion } from "framer-motion";
  6→import { getMonthlyHottestJournals, searchJournals, searchUsers } from "../../../../API/Api";
  7→import { useAuth } from "../../../Context/useAuth";
  8→import { handleClickProfile } from "../../../../helpers/handleClicks";
  9→import ParseContent from "../postCards/parseData";
 10→import CalculateText from "../postCards/calculateReadingTime";
 11→import formatPostDate from "../../../../helpers/formatDateString";
 12→import VerifiedBadge from "../../Badge/VerifiedBadge";
 13→import { handleImageFallback } from "../../../utils/handleImageFallback";
 14→import { useAddViewsMutation } from "../../../utils/useMutation";
 15→import UserSearchResults from "./UserSearchResults";
 16→import "../postCards/postcards.css";
 17→import "./explore.css";
 18→import "./userSearch.css";
 19→
 20→const getHotScore = (journal) => {
 21→    if(typeof journal?.hot_score === "number"){
 22→        return journal.hot_score;
 23→    }
 24→
 25→    const likes = journal?.like_count?.[0]?.count || 0;
 26→    const comments = journal?.comment_count?.[0]?.count || 0;
 27→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 28→    const views = journal?.views || 0;
 29→
 30→    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 31→};
 32→
 33→const FlameIcon = ({ className }) => (
 34→    <svg className={className} viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
 35→        <path d="M12 2C10.97 6.5 6 9.5 6 14C6 17.31 8.69 20 12 20C15.31 20 18 17.31 18 14C18 9.5 13.03 6.5 12 2Z" fill="currentColor"/>
 36→        <path d="M12 20C10.34 20 9 18.66 9 17C9 15 12 12 12 12C12 12 15 15 15 17C15 18.66 13.66 20 12 20Z" fill="var(--bg-card)" opacity="0.6"/>
 37→    </svg>
 38→);
 39→
 40→const HeroCard = ({ journal, parsedContent, hotScore, onClick }) => (
 41→    <motion.div
 42→        className="explore-hero-wrap"
 43→        initial={{ opacity: 0, y: 20 }}
 44→        animate={{ opacity: 1, y: 0 }}
 45→        transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
 46→    >
 47→        <div className="explore-hero-glow" />
 48→        <div
 49→            className="explore-hero-card"
 50→            onClick={() => onClick(journal.id)}
 51→            role="button"
 52→            tabIndex={0}
 53→            onKeyDown={(e) => {
 54→                if(e.key === "Enter" || e.key === " "){
 55→                    e.preventDefault();
 56→                    onClick(journal.id);
 57→                }
 58→            }}
 59→        >
 60→
 61→        {parsedContent?.firstImage && (
 62→            <div className="explore-hero-image-wrap">
 63→                <img
 64→                    className="explore-hero-image"
 65→                    src={parsedContent.firstImage.src}
 66→                    alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
 67→                    loading="eager"
 68→                    onError={handleImageFallback}
 69→                />
 70→                <div className="explore-hero-image-overlay" />
 71→            </div>
 72→        )}
 73→
 74→        <div className={`explore-hero-body ${parsedContent?.firstImage ? "explore-hero-body--has-image" : ""}`}>
 75→            <div className="explore-hero-badge">
 76→                <FlameIcon className="explore-hero-flame" />
 77→                <span className="explore-hero-badge-text">#1 Hottest</span>
 78→            </div>
 79→
 80→            <h2 className="explore-hero-title">
 81→                {journal?.title?.length > 80 ? `${journal.title.substring(0, 80)}...` : (journal?.title || "Untitled")}
 82→            </h2>
 83→
 84→            <p className="explore-hero-excerpt">{parsedContent?.slicedText}</p>
 85→
 86→            <div className="explore-hero-footer">
 87→                <div className="explore-hero-author">
 88→                    <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
 89→                        <img
 90→                            loading="lazy"
 91→                            className="user-info-avatar"
 92→                            src={journal?.users?.image_url || "/assets/profile.jpg"}
 93→                            alt={`${journal?.users?.name || "User"} profile picture`}
 94→                        />
 95→                    </div>
 96→                    <div className="user-name-container">
 97→                        <p className="user-newsfeed-name">{journal?.users?.name || "Unknown author"}</p>
 98→                        <VerifiedBadge badge={journal?.users?.badge} size={14} />
 99→                    </div>
100→                    <div className="name-info-separator">•</div>
101→                    <p className="user-post-date">{formatPostDate(journal?.created_at)}</p>
102→                </div>
103→
104→                <div className="explore-hero-stats">
105→                    <div className="explore-hero-score-pill">
106→                        <FlameIcon className="explore-hero-score-flame" />
107→                        {hotScore}
108→                    </div>
109→                    <div className="reading-time-container">
110→                        <p className="reading-time-text">{CalculateText(parsedContent?.wholeText)}</p>
111→                    </div>
112→                </div>
113→            </div>
114→        </div>
115→        </div>
116→    </motion.div>
117→);
118→
119→const RunnerCard = ({ journal, index, parsedContent, hotScore, onClick }) => (
120→    <motion.div
121→        className="explore-runner-card"
122→        onClick={() => onClick(journal.id)}
123→        role="button"
124→        tabIndex={0}
125→        onKeyDown={(e) => {
126→            if(e.key === "Enter" || e.key === " "){
127→                e.preventDefault();
128→                onClick(journal.id);
129→            }
130→        }}
131→        initial={{ opacity: 0, y: 14 }}
132→        animate={{ opacity: 1, y: 0 }}
133→        transition={{ duration: 0.4, delay: 0.08 * index, ease: [0.22, 1, 0.36, 1] }}
134→    >
135→        <div className="explore-runner-rank-col">
136→            <span className={`explore-runner-rank ${index <= 2 ? "explore-runner-rank--top" : ""}`}>
137→                {index + 1}
138→            </span>
139→        </div>
140→
141→        <div className="explore-runner-body">
142→            <h3 className="explore-runner-title">
143→                {journal?.title?.length > 60 ? `${journal.title.substring(0, 60)}...` : (journal?.title || "Untitled")}
144→            </h3>
145→            <p className="explore-runner-excerpt">{parsedContent?.slicedText}</p>
146→            <div className="explore-runner-meta">
147→                <div className="explore-runner-author">
148→                    <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
149→                        <img
150→                            loading="lazy"
151→                            className="user-info-avatar"
152→                            src={journal?.users?.image_url || "/assets/profile.jpg"}
153→                            alt={`${journal?.users?.name || "User"} profile picture`}
154→                        />
155→                    </div>
156→                    <p className="user-newsfeed-name">{journal?.users?.name || "Unknown author"}</p>
157→                    <VerifiedBadge badge={journal?.users?.badge} size={12} />
158→                    <div className="name-info-separator">•</div>
159→                    <p className="user-post-date">{formatPostDate(journal?.created_at)}</p>
160→                </div>
161→                <div className="explore-runner-stats">
162→                    <div className="explore-score-pill">
163→                        <FlameIcon className="explore-runner-flame-icon" />
164→                        {hotScore}
165→                    </div>
166→                    <div className="reading-time-container">
167→                        <p className="reading-time-text">{CalculateText(parsedContent?.wholeText)}</p>
168→                    </div>
169→                </div>
170→            </div>
171→        </div>
172→
173→        {parsedContent?.firstImage && (
174→            <div className="explore-runner-thumb-wrap">
175→                <img
176→                    className="explore-runner-thumb"
177→                    src={parsedContent.firstImage.src}
178→                    alt=""
179→                    loading="lazy"
180→                    onError={handleImageFallback}
181→                />
182→            </div>
183→        )}
184→    </motion.div>
185→);
186→
187→const ExplorePage = () => {
188→    const navigate = useNavigate();
189→    const { session, user, openAuthModal } = useAuth();
190→    const userId = user?.userData?.[0]?.id || null;
191→    const mutateViews = useAddViewsMutation(session);
192→    const searchShellRef = useRef(null);
193→
194→    const [searchInput, setSearchInput] = useState("");
195→    const [debouncedSearchInput, setDebouncedSearchInput] = useState("");
196→    const [committedSearchQuery, setCommittedSearchQuery] = useState("");
197→    const [isSearchFocused, setIsSearchFocused] = useState(false);
198→    const [searchType, setSearchType] = useState("posts");
199→    const onClickProfile = handleClickProfile(navigate);
200→    const currentUtcMonthKey = `${new Date().getUTCFullYear()}-${String(new Date().getUTCMonth() + 1).padStart(2, "0")}`;
201→
202→    useEffect(() => {
203→        const timer = setTimeout(() => {
204→            setDebouncedSearchInput(searchInput.trim());
205→        }, 350);
206→
207→        return () => clearTimeout(timer);
208→    }, [searchInput]);
209→
210→    const isSearchMode = committedSearchQuery.length >= 2;
211→
212→    const { data: feedData, isLoading: isLoadingFeed } = useQuery({
213→        queryKey: ["explore-hottest-monthly-feed", userId, currentUtcMonthKey],
214→        queryFn: () => getMonthlyHottestJournals(userId, 10),
215→        refetchOnWindowFocus: false,
216→        staleTime: 15 * 1000,
217→    });
218→
219→    const {
220→        data: searchData,
221→        isLoading: isLoadingSearch,
222→        isFetching: isFetchingSearch,
223→        error: searchError,
224→    } = useQuery({
225→        queryKey: ["explore-search", userId, committedSearchQuery],
226→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
227→        enabled: isSearchMode,
228→        refetchOnWindowFocus: false,
229→        staleTime: 10 * 1000,
230→    });
231→
232→    const {
233→        data: suggestionData,
234→        isLoading: isSuggestionsLoading,
235→    } = useQuery({
236→        queryKey: ["explore-suggestions", userId, debouncedSearchInput],
237→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
238→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === "posts",
239→        refetchOnWindowFocus: false,
240→        staleTime: 10 * 1000,
241→    });
242→
243→    const {
244→        data: userSuggestionData,
245→        isLoading: isUserSuggestionsLoading,
246→    } = useQuery({
247→        queryKey: ["user-suggestions", debouncedSearchInput],
248→        queryFn: () => searchUsers(debouncedSearchInput, 6),
249→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === "people",
250→        refetchOnWindowFocus: false,
251→        staleTime: 10 * 1000,
252→    });
253→
254→    const journals = isSearchMode ? (searchData?.data || []) : (feedData?.data || []);
255→    const isLoading = isSearchMode && searchType === "posts" ? isLoadingSearch : isLoadingFeed;
256→    const suggestionItems = searchType === "people" ? (userSuggestionData?.data || []) : (suggestionData?.data || []);
257→    const isSugLoading = searchType === "people" ? isUserSuggestionsLoading : isSuggestionsLoading;
258→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
259→
260→    const handleSubmitSearch = (rawQuery) => {
261→        const normalizedQuery = typeof rawQuery === "string" ? rawQuery.trim() : "";
262→        if(normalizedQuery.length < 2){
263→            setCommittedSearchQuery("");
264→            return;
265→        }
266→
267→        setCommittedSearchQuery(normalizedQuery);
268→        setSearchInput(normalizedQuery);
269→        setIsSearchFocused(false);
270→    };
271→
272→    const handleClearSearch = () => {
273→        setSearchInput("");
274→        setDebouncedSearchInput("");
275→        setCommittedSearchQuery("");
276→        setIsSearchFocused(false);
277→        setSearchType("posts");
278→    };
279→
280→    const handleSearchInputKeyDown = (e) => {
281→        if(e.key === "Enter"){
282→            e.preventDefault();
283→            handleSubmitSearch(searchInput);
284→        }
285→
286→        if(e.key === "Escape"){
287→            setIsSearchFocused(false);
288→        }
289→    };
290→
291→    const handleClickSuggestion = (journal) => {
292→        if(!journal?.id){
293→            return;
294→        }
295→        if(!session){
296→            openAuthModal();
297→            return;
298→        }
299→        setIsSearchFocused(false);
300→        if(journal?.title){
301→            setSearchInput(journal.title);
302→            setDebouncedSearchInput(journal.title);
303→        }
304→        const formadata = new FormData();
305→        formadata.append('journalId', journal.id);
306→        mutateViews.mutate(formadata);
307→        navigate(`/home/post/${journal.id}`);
308→    };
309→
310→    const handleClickPost = (journalId) => {
311→        if(!journalId){
312→            return;
313→        }
314→        if(!session){
315→            openAuthModal();
316→            return;
317→        }
318→        const formadata = new FormData();
319→        formadata.append('journalId', journalId);
320→        mutateViews.mutate(formadata);
321→        navigate(`/home/post/${journalId}`);
322→    };
323→
324→    useEffect(() => {
325→        const handleOutsideSearchClick = (e) => {
326→            if(searchShellRef.current && !searchShellRef.current.contains(e.target)){
327→                setIsSearchFocused(false);
328→            }
329→        };
330→
331→        window.addEventListener("mousedown", handleOutsideSearchClick);
332→        return () => window.removeEventListener("mousedown", handleOutsideSearchClick);
333→    }, []);
334→
335→    if(isLoading && searchType === "posts"){
336→        return (
337→            <div className="postcards-parent-loading-container">
338→                <MoonLoader loading={true} color="var(--loader-color)" speedMultiplier={1} size={20} />
339→            </div>
340→        );
341→    }
342→
343→    const heroJournal = !isSearchMode && journals.length > 0 ? journals[0] : null;
344→    const runnerJournals = !isSearchMode && journals.length > 1 ? journals.slice(1) : isSearchMode ? journals : [];
345→
346→    return (
347→        <div className="explore-page-container">
348→            <div className="search-shell" role="search" ref={searchShellRef}>
349→                <div className="search-top-bar">
350→                    <div className="search-input-wrap">
351→                        <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
352→                            <path d="M10 2a8 8 0 1 0 4.906 14.32l4.387 4.387a1 1 0 0 0 1.414-1.414L16.32 14.906A8 8 0 0 0 10 2Zm0 2a6 6 0 1 1 0 12a6 6 0 0 1 0-12Z"/>
353→                        </svg>
354→                        <input
355→                            type="search"
356→                            value={searchInput}
357→                            onChange={(e) => setSearchInput(e.target.value)}
358→                            onFocus={() => setIsSearchFocused(true)}
359→                            onKeyDown={handleSearchInputKeyDown}
360→                            placeholder={searchType === "people" ? "Search people..." : "Search posts..."}
361→                            className="search-input"
362→                            aria-label={searchType === "people" ? "Search people" : "Search posts"}
363→                        />
364→                    </div>
365→                    {searchInput ? (
366→                        <button type="button" className="search-clear-btn" onClick={handleClearSearch}>
367→                            Clear
368→                        </button>
369→                    ) : null}
370→                    {isSearchMode ? (
371→                        <span className="search-mode-pill">
372→                            {isFetchingSearch ? "Searching..." : "Matched"}
373→                        </span>
374→                    ) : (
375→                        <span className="search-mode-pill">
376→                            {isSuggestionsLoading && showSuggestions ? "Suggesting..." : "Search"}
377→                        </span>
378→                    )}
379→                </div>
380→                {showSuggestions && (
381→                    <div className="search-suggestions-dropdown">
382→                        {isSugLoading ? (
383→                            <div className="search-suggestion-item search-suggestion-muted">Searching...</div>
384→                        ) : suggestionItems.length > 0 ? (
385→                            searchType === "people" ? (
386→                                suggestionItems.map((item) => (
387→                                    <button
388→                                        key={item.id}
389→                                        type="button"
390→                                        className="search-suggestion-user"
391→                                        onClick={(e) => {
392→                                            setIsSearchFocused(false);
393→                                            onClickProfile(e, userId, item.id, item.username);
394→                                        }}
395→                                    >
396→                                        <img
397→                                            className="search-suggestion-user-avatar"
398→                                            src={item.image_url || "/assets/profile.jpg"}
399→                                            alt=""
400→                                            loading="lazy"
401→                                        />
402→                                        <div className="search-suggestion-user-info">
403→                                            <span className="search-suggestion-user-name">{item.name || "Unknown"}</span>
404→                                            {item.username && (
405→                                                <span className="search-suggestion-user-handle">@{item.username}</span>
406→                                            )}
407→                                        </div>
408→                                    </button>
409→                                ))
410→                            ) : (
411→                                suggestionItems.map((item) => (
412→                                    <button
413→                                        key={item.id}
414→                                        type="button"
415→                                        className="search-suggestion-item"
416→                                        onClick={() => handleClickSuggestion(item)}
417→                                    >
418→                                        <span className="search-suggestion-title">{item.title || "Untitled"}</span>
419→                                        <span className="search-suggestion-meta">{item?.users?.name || "Unknown author"}</span>
420→                                    </button>
421→                                ))
422→                            )
423→                        ) : (
424→                            <div className="search-suggestion-item search-suggestion-muted">No suggestions</div>
425→                        )}
426→                    </div>
427→                )}
428→                {(isSearchFocused || searchInput.length > 0 || isSearchMode) && (
429→                    <div className="search-type-toggle">
430→                        <button
431→                            type="button"
432→                            className={`search-type-btn ${searchType === "posts" ? "search-type-btn--active" : ""}`}
433→                            onClick={() => setSearchType("posts")}
434→                        >
435→                            Posts
436→                        </button>
437→                        <button
438→                            type="button"
439→                            className={`search-type-btn ${searchType === "people" ? "search-type-btn--active" : ""}`}
440→                            onClick={() => setSearchType("people")}
441→                        >
442→                            People
443→                        </button>
444→                    </div>
445→                )}
446→            </div>
447→
448→            {isSearchMode && searchType === "people" ? (
449→                <>
450→                    <div className="explore-section-title">
451→                        People
452→                    </div>
453→                    <UserSearchResults searchQuery={committedSearchQuery} />
454→                </>
455→            ) : (
456→            <>
457→            <div className="explore-section-title">
458→                {isSearchMode ? "Search results" : "Hottest posts"}
459→            </div>
460→
461→            {journals.length === 0 && (
462→                <div className="search-empty-state">
463→                    {searchError
464→                        ? "Search failed. Please try again."
465→                        : isSearchMode
466→                            ? "No matching posts found."
467→                            : "No posts available right now."}
468→                </div>
469→            )}
470→
471→            {heroJournal && (() => {
472→                const parsedContent = ParseContent(heroJournal?.content);
473→                const hotScore = getHotScore(heroJournal);
474→                return (
475→                    <div className="explore-hero-section">
476→                        <HeroCard
477→                            journal={heroJournal}
478→                            parsedContent={parsedContent}
479→                            hotScore={hotScore}
480→                            onClick={handleClickPost}
481→                        />
482→                    </div>
483→                );
484→            })()}
485→
486→            {runnerJournals.length > 0 && (
487→                <div className={`explore-runners-section ${isSearchMode ? "explore-runners-section--search" : ""}`}>
488→                    {!isSearchMode && (
489→                        <div className="explore-section-title explore-section-title--runners">
490→                            Runners up
491→                        </div>
492→                    )}
493→                    <div className="explore-runners-list">
494→                        {runnerJournals.map((journal, i) => {
495→                            const parsedContent = ParseContent(journal?.content);
496→                            const hotScore = getHotScore(journal);
497→                            const displayIndex = isSearchMode ? i : i + 1;
498→
499→                            return isSearchMode ? (
500→                                <motion.div
501→                                    key={journal.id}
502→                                    className="cards"
503→                                    onClick={() => handleClickPost(journal.id)}
504→                                    role="button"
505→                                    tabIndex={0}
506→                                    onKeyDown={(e) => {
507→                                        if(e.key === "Enter" || e.key === " "){
508→                                            e.preventDefault();
509→                                            handleClickPost(journal.id);
510→                                        }
511→                                    }}
512→                                    initial={{ opacity: 0, y: 14 }}
513→                                    animate={{ opacity: 1, y: 0 }}
514→                                    transition={{ duration: 0.35, delay: 0.06 * i, ease: [0.22, 1, 0.36, 1] }}
515→                                >
516→                                    <div className="explore-rank">#{i + 1}</div>
517→
518→                                    {parsedContent?.firstImage && (
519→                                        <img
520→                                            className="card-image-banner"
521→                                            src={parsedContent.firstImage.src}
522→                                            alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
523→                                            loading="lazy"
524→                                            onError={handleImageFallback}
525→                                        />
526→                                    )}
527→
528→                                    <div className="card-content">
529→                                        <div className="content-container">
530→                                            <div className="feed-text-content-container">
531→                                                <div className="feed-title-content">
532→                                                    <h2 className="feed-title">
533→                                                        {journal?.title?.length > 55 ? `${journal.title.substring(0, 55)}...` : (journal?.title || "Untitled")}
534→                                                    </h2>
535→                                                </div>
536→                                                <p className="feed-text-content">{parsedContent?.slicedText}</p>
537→                                            </div>
538→                                        </div>
539→                                    </div>
540→
541→                                    <div className="card-icons-container">
542→                                        <div className="user-info-child-container">
543→                                            <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
544→                                                <img
545→                                                    loading="lazy"
546→                                                    className="user-info-avatar"
547→                                                    src={journal?.users?.image_url || "/assets/profile.jpg"}
548→                                                    alt={`${journal?.users?.name || "User"} profile picture`}
549→                                                />
550→                                            </div>
551→                                            <div className="user-name-container">
552→                                                <p className="user-newsfeed-name">{journal?.users?.name || "Unknown author"}</p>
553→                                                <VerifiedBadge badge={journal?.users?.badge} size={14} />
554→                                            </div>
555→                                            <div className="name-info-separator">•</div>
556→                                            <p className="user-post-date">{formatPostDate(journal?.created_at)}</p>
557→                                        </div>
558→
559→                                        <div className="explore-meta-right">
560→                                            <div className="explore-score-pill">
561→                                                Hot score: {hotScore}
562→                                            </div>
563→                                            <div className="reading-time-container">
564→                                                <p className="reading-time-text">{CalculateText(parsedContent?.wholeText)}</p>
565→                                            </div>
566→                                        </div>
567→                                    </div>
568→                                </motion.div>
569→                            ) : (
570→                                <RunnerCard
571→                                    key={journal.id}
572→                                    journal={journal}
573→                                    index={displayIndex}
574→                                    parsedContent={parsedContent}
575→                                    hotScore={hotScore}
