 17→const UserSearchResults = ({ searchQuery }) => {
 18→    const navigate = useNavigate();
 19→    const { user } = useAuth();
 20→    const loggedInUserId = user?.userData?.[0]?.id || null;
 21→    const onClickProfile = handleClickProfile(navigate);
 22→
 23→    const {
 24→        data: searchData,
 25→        isLoading,
 26→        error,
 27→    } = useQuery({
 28→        queryKey: ["user-search", searchQuery],
 29→        queryFn: () => searchUsers(searchQuery, 10),
 30→        enabled: searchQuery.length >= 2,
 31→        refetchOnWindowFocus: false,
 32→        staleTime: 10 * 1000,
 33→    });
 34→
 35→    const users = searchData?.data || [];
 36→
 37→    if(isLoading){
 38→        return (
 39→            <div className="postcards-parent-loading-container">
 40→                <MoonLoader loading={true} color="var(--loader-color)" speedMultiplier={1} size={20} />
 41→            </div>
 42→        );
 43→    }
 44→
 45→    if(error){
 46→        return (
 47→            <div className="search-empty-state">
 48→                Search failed. Please try again.
 49→            </div>
 50→        );
 51→    }
 52→
 53→    if(users.length === 0){
 54→        return (
 55→            <div className="search-empty-state">
 56→                No matching people found.
 57→            </div>
 58→        );
 59→    }
 60→
 61→    return (
 62→        <div className="user-search-results">
 63→            {users.map((userItem, i) => (
 64→                <motion.div
 65→                    key={userItem.id}
 66→                    className="user-search-card"
 67→                    onClick={(e) => onClickProfile(e, loggedInUserId, userItem.id, userItem.username)}
 68→                    role="button"
 69→                    tabIndex={0}
 70→                    onKeyDown={(e) => {
 71→                        if(e.key === "Enter" || e.key === " "){
 72→                            e.preventDefault();
 73→                            onClickProfile(e, loggedInUserId, userItem.id, userItem.username);
 74→                        }
 75→                    }}
 76→                    initial={{ opacity: 0, y: 8 }}
 77→                    animate={{ opacity: 1, y: 0 }}
 78→                    transition={{ duration: 0.35, delay: 0.04 * i, ease: [0.22, 1, 0.36, 1] }}
 79→                >
 80→                    <div className="user-search-avatar-wrap">
 81→                        <div className={`user-avatar-container ${userItem.badge === "legend" ? "avatar-ring-legend" : userItem.badge === "og" ? "avatar-ring-og" : ""}`}>
 82→                            <img
 83→                                loading="lazy"
 84→                                className="user-info-avatar"
 85→                                src={userItem.image_url || "/assets/profile.jpg"}
 86→                                alt={`${userItem.name || "User"} profile picture`}
 87→                            />
 88→                        </div>
 89→                    </div>
 90→                    <div className="user-search-info">
 91→                        <div className="user-search-name-row">
 92→                            <p className="user-search-name">{userItem.name || "Unknown"}</p>
